                        className="w-full h-56 p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] font-mono text-lg text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all shadow-inner"
                      />
                    </div>

                    <div className="grid sm:grid-cols-2 gap-8">
                      {formData.options.map((opt, i) => (
                        <div key={i} className="space-y-3">
                          <label className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em] px-3 flex justify-between">
                            <span>Index {String.fromCharCode(65 + i)}</span>
                            {opt === formData.answerText && <span className="text-emerald-500">Correct Target</span>}
                          </label>
                          <input 
                            type="text" 
                            value={opt} 
                            onChange={e => {
                              const newOpts = [...formData.options];
                              newOpts[i] = e.target.value;
                              setFormData({...formData, options: newOpts});
                            }}
                            className={`w-full p-5 rounded-2xl font-bold text-lg outline-none transition-all shadow-sm ${opt === formData.answerText ? 'bg-emerald-50 border-2 border-emerald-200 text-emerald-900' : 'bg-slate-50 border-2 border-slate-100 text-slate-700 focus:border-blue-500'}`}
                          />
                        </div>
                      ))}
                    </div>

                    <div className="space-y-4">
                      <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                        <Beaker size={18} className="text-blue-500" /> Scientific Core Rationale
                      </div>
                      <textarea 
                        value={formData.explanation} 
                        onChange={e => setFormData({...formData, explanation: e.target.value})}
                        className="w-full h-56 p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] font-mono text-lg text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all shadow-inner"
                      />
                    </div>
                  </div>
                </div>
              ) : (
                <div className="bg-white rounded-[4rem] shadow-[0_60px_150px_rgba(0,0,0,0.1)] border border-slate-100 overflow-hidden flex flex-col group transition-all duration-700 hover:shadow-[0_80px_200px_rgba(0,0,0,0.12)]">
                  <div className="bg-slate-950 p-10 flex justify-between items-center">
                    <span className="text-xs font-black text-blue-400 uppercase tracking-[0.5em] font-mono flex items-center gap-3">
                       <ShieldCheck size={18} className="animate-pulse" /> Data Matrix V4
                    </span>
