              )}
            </div>

            <div className="lg:col-span-4 space-y-12">
              <div className="bg-white rounded-[3.5rem] p-12 border border-slate-100 shadow-3xl space-y-16 sticky top-36">
                <div className="space-y-10">
                  <h4 className="font-black text-slate-900 uppercase tracking-[0.3em] text-xs border-b border-slate-100 pb-8 flex items-center gap-3">
                    <ImageIcon size={20} className="text-blue-500" /> Digital Assets
                  </h4>

                  <div className="space-y-10">
                    <div className="space-y-4">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] px-2">Primary Asset Layer</label>
                      <input 
                        type="url" 
                        value={formData.questionImage}
                        onChange={e => setFormData({...formData, questionImage: e.target.value})}
                        className="w-full px-8 py-6 rounded-2xl bg-slate-50 border-2 border-slate-50 text-xs font-bold text-slate-600 focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner" 
                        placeholder="Diagram URL"
